import axios from 'axios';

// Build API base URL using the current host so the frontend works when accessed
// via the machine IP (e.g. http://172.31.182.178:3000)
const backendHost = window?.location?.hostname || 'localhost';
const isLocalHost = backendHost === 'localhost' || backendHost === '127.0.0.1';
const primaryBaseUrl = `http://${backendHost}:8000/api/`;
const fallbackBaseUrl = isLocalHost ? 'http://127.0.0.1:8000/api/' : primaryBaseUrl;
const API = axios.create({ baseURL: primaryBaseUrl });

function getToken(){
  return localStorage.getItem('access');
}

API.interceptors.request.use(config => {
  const token = getToken();
  if(token){
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

function isNetworkError(error) {
  return !error.response || error.message === 'Network Error' || error.code === 'ECONNREFUSED';
}

async function postWithFallback(path, data){
  try {
    return await axios.post(`${primaryBaseUrl}${path}`, data);
  } catch (error) {
    if (isNetworkError(error) && fallbackBaseUrl !== primaryBaseUrl) {
      return await axios.post(`${fallbackBaseUrl}${path}`, data);
    }
    throw error;
  }
}

async function getWithFallback(path){
  try {
    return await axios.get(`${primaryBaseUrl}${path}`);
  } catch (error) {
    if (isNetworkError(error) && fallbackBaseUrl !== primaryBaseUrl) {
      return await axios.get(`${fallbackBaseUrl}${path}`);
    }
    throw error;
  }
}

export async function login(username, password){
  const url = `http://${backendHost}:8000/api/auth/login/`;
  try {
    const res = await axios.post(url, {username, password});
    localStorage.setItem('access', res.data.access);
    localStorage.setItem('refresh', res.data.refresh);
    return res.data;
  } catch (error) {
    if (error.code === 'ECONNREFUSED' || !error.response) {
      const res = await axios.post('http://127.0.0.1:8000/api/auth/login/', {username, password});
      localStorage.setItem('access', res.data.access);
      localStorage.setItem('refresh', res.data.refresh);
      return res.data;
    }
    throw error;
  }
}

export async function register(data){
  const res = await postWithFallback('auth/register/', data);
  return res.data;
}

export async function getMe(){
  const token = getToken();
  if (!token) return null;

  try{
    const res = await getWithFallback('auth/me/');
    return res.data;
  }catch(e){
    // Token invalid or expired — clear storage to force re-login
    localStorage.removeItem('access');
    localStorage.removeItem('refresh');
    return null;
  }
}

export async function getProjects(){
  const res = await API.get('projects/');
  return res.data;
}

export async function getProject(id){
  const res = await API.get(`projects/${id}/`);
  return res.data;
}

export async function createProject(payload){
  const res = await API.post('projects/', payload);
  return res.data;
}

export async function getNotifications(){
  const res = await API.get('notifications/');
  return res.data;
}

export async function createTask(payload){
  const res = await API.post('tasks/', payload);
  return res.data;
}

export async function updateTask(id, payload){
  const res = await API.patch(`tasks/${id}/`, payload);
  return res.data;
}

export async function addComment(payload){
  const res = await API.post('comments/', payload);
  return res.data;
}

export default API;
